const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const app = express();
app.use(express.json());

const MONGO_URI = process.env.MONGO_URI || 'mongodb://localhost:27017';
const DB_NAME = process.env.DB_NAME || 'queryservice';

let db;

async function connectToMongo() {
  const client = new MongoClient(MONGO_URI);
  await client.connect();
  db = client.db(DB_NAME);
  console.log('Connected to MongoDB');
  return client;
}

// Sanitize user input to prevent NoSQL injection
function sanitizeFilter(obj) {
  if (obj === null || obj === undefined) {
    return obj;
  }

  if (typeof obj === 'string' || typeof obj === 'number' || typeof obj === 'boolean') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => sanitizeFilter(item));
  }

  if (typeof obj === 'object') {
    const sanitized = {};
    const allowedOperators = new Set([
      '$gt', '$gte', '$lt', '$lte', '$eq', '$ne',
      '$in', '$nin', '$regex', '$options',
      '$exists', '$type',
      '$and', '$or', '$nor', '$not',
      '$elemMatch', '$size', '$all',
      '$mod', '$text', '$search', '$language',
      '$caseSensitive', '$diacriticSensitive'
    ]);

    // Block dangerous operators that could cause server-side code execution or data exfiltration
    const blockedOperators = new Set([
      '$where', '$accumulator', '$function',
      '$expr', '$jsonSchema',
      '$comment'
    ]);

    for (const key of Object.keys(obj)) {
      if (key.startsWith('$') && blockedOperators.has(key)) {
        throw new Error(`Operator "${key}" is not allowed for security reasons`);
      }

      if (key.startsWith('$') && !allowedOperators.has(key)) {
        throw new Error(`Unsupported operator: "${key}"`);
      }

      sanitized[key] = sanitizeFilter(obj[key]);
    }

    return sanitized;
  }

  return obj;
}

// Convert special string patterns to proper types
function convertTypes(obj) {
  if (obj === null || obj === undefined) {
    return obj;
  }

  if (typeof obj === 'string') {
    // Convert ObjectId strings
    if (/^[0-9a-fA-F]{24}$/.test(obj)) {
      // Don't auto-convert, let it be explicit
      return obj;
    }
    return obj;
  }

  if (typeof obj !== 'object') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => convertTypes(item));
  }

  const converted = {};
  for (const [key, value] of Object.entries(obj)) {
    if (key === '_id' && typeof value === 'string' && /^[0-9a-fA-F]{24}$/.test(value)) {
      converted[key] = new ObjectId(value);
    } else if (key === '$oid' && typeof value === 'string') {
      return new ObjectId(value);
    } else if (key === '$date' && typeof value === 'string') {
      return new Date(value);
    } else if (key === '$regex' && typeof value === 'string') {
      // Keep $regex as-is, MongoDB driver handles it
      converted[key] = value;
    } else {
      converted[key] = convertTypes(value);
    }
  }

  return converted;
}

// Validate collection name to prevent access to system collections
function validateCollectionName(name) {
  if (!name || typeof name !== 'string') {
    throw new Error('Collection name is required and must be a string');
  }
  if (name.startsWith('system.')) {
    throw new Error('Access to system collections is not allowed');
  }
  if (!/^[a-zA-Z0-9_.-]+$/.test(name)) {
    throw new Error('Invalid collection name');
  }
  return name;
}

// POST /api/query/:collection - Query documents with filters
app.post('/api/query/:collection', async (req, res) => {
  try {
    const collectionName = validateCollectionName(req.params.collection);
    const {
      filter = {},
      projection = null,
      sort = null,
      limit = 100,
      skip = 0
    } = req.body;

    // Cap the limit to prevent excessive data retrieval
    const cappedLimit = Math.min(Math.max(1, parseInt(limit) || 100), 1000);
    const validSkip = Math.max(0, parseInt(skip) || 0);

    const sanitizedFilter = sanitizeFilter(filter);
    const convertedFilter = convertTypes(sanitizedFilter);

    let sanitizedProjection = null;
    if (projection) {
      sanitizedProjection = sanitizeFilter(projection);
    }

    let sanitizedSort = null;
    if (sort) {
      sanitizedSort = sanitizeFilter(sort);
    }

    const collection = db.collection(collectionName);

    let cursor = collection.find(convertedFilter);

    if (sanitizedProjection) {
      cursor = cursor.project(sanitizedProjection);
    }

    if (sanitizedSort) {
      cursor = cursor.sort(sanitizedSort);
    }

    cursor = cursor.skip(validSkip).limit(cappedLimit);

    const documents = await cursor.toArray();
    const totalCount = await collection.countDocuments(convertedFilter);

    res.json({
      success: true,
      data: documents,
      metadata: {
        total: totalCount,
        limit: cappedLimit,
        skip: validSkip,
        returned: documents.length
      }
    });
  } catch (error) {
    console.error('Query error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

// POST /api/query/:collection/aggregate - Run aggregation pipelines
app.post('/api/query/:collection/aggregate', async (req, res) => {
  try {
    const collectionName = validateCollectionName(req.params.collection);
    const { pipeline = [] } = req.body;

    if (!Array.isArray(pipeline)) {
      throw new Error('Pipeline must be an array');
    }

    // Block dangerous aggregation stages
    const blockedStages = new Set(['$out', '$merge', '$collStats', '$indexStats', '$planCacheStats', '$currentOp', '$listSessions']);

    for (const stage of pipeline) {
      const stageKeys = Object.keys(stage);
      for (const key of stageKeys) {
        if (blockedStages.has(key)) {
          throw new Error(`Aggregation stage "${key}" is not allowed`);
        }
      }
    }

    // Ensure there's a $limit stage to prevent excessive results
    const hasLimit = pipeline.some(stage => '$limit' in stage);
    if (!hasLimit) {
      pipeline.push({ $limit: 1000 });
    }

    const sanitizedPipeline = pipeline.map(stage => {
      const sanitized = sanitizeFilter(stage);
      return convertTypes(sanitized);
    });

    const collection = db.collection(collectionName);
    const results = await collection.aggregate(sanitizedPipeline).toArray();

    res.json({
      success: true,
      data: results,
      metadata: {
        returned: results.length
      }
    });
  } catch (error) {
    console.error('Aggregation error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

